<template>
  <view class="admin-order">
    <view class="page-header">
      <text class="page-title">订单管理</text>
    </view>

    <!-- 状态筛选 -->
    <view class="filter-bar">
      <view
        class="filter-item"
        :class="{ active: currentStatus === null }"
        @click="filterByStatus(null)"
      >
        <text>全部</text>
      </view>
      <view
        class="filter-item"
        :class="{ active: currentStatus === 0 }"
        @click="filterByStatus(0)"
      >
        <text>待支付</text>
      </view>
      <view
        class="filter-item"
        :class="{ active: currentStatus === 1 }"
        @click="filterByStatus(1)"
      >
        <text>已支付</text>
      </view>
      <view
        class="filter-item"
        :class="{ active: currentStatus === 2 }"
        @click="filterByStatus(2)"
      >
        <text>已发货</text>
      </view>
      <view
        class="filter-item"
        :class="{ active: currentStatus === 3 }"
        @click="filterByStatus(3)"
      >
        <text>已完成</text>
      </view>
      <view
        class="filter-item"
        :class="{ active: currentStatus === 5 }"
        @click="filterByStatus(5)"
      >
        <text>已退款</text>
      </view>
    </view>

    <!-- 订单列表 -->
    <view class="order-list">
      <view class="order-card" v-for="item in orderList" :key="item.id">
        <view class="order-header">
          <text class="order-no">{{ item.orderNo }}</text>
          <text :class="['order-status', 'status-' + item.status]">{{ getStatusText(item.status) }}</text>
        </view>
        <view class="order-body">
          <view class="order-info">
            <text class="info-item">金额: ¥{{ item.totalAmount }}</text>
            <text class="info-item">用户ID: {{ item.userId }}</text>
            <text class="info-item">时间: {{ item.createTime }}</text>
          </view>
        </view>
        <view class="order-footer" v-if="item.status === 1 || item.status === 2">
          <button
            class="action-btn ship-btn"
            v-if="item.status === 1"
            @click="handleShip(item)"
          >发货</button>
          <button
            class="action-btn refund-btn"
            v-if="item.status === 1 || item.status === 2"
            @click="handleRefund(item)"
          >退款</button>
        </view>
      </view>

      <view class="empty" v-if="orderList.length === 0 && !loading">
        <text>暂无订单</text>
      </view>
    </view>

    <!-- 底部导航 -->
    <view class="admin-nav">
      <view class="nav-item" @click="navigateTo('/pages/admin/product/list')">
        <text>商品</text>
      </view>
      <view class="nav-item" @click="navigateTo('/pages/admin/category/list')">
        <text>分类</text>
      </view>
      <view class="nav-item active">
        <text>订单</text>
      </view>
      <view class="nav-item" @click="navigateTo('/pages/admin/user/list')">
        <text>用户</text>
      </view>
    </view>
  </view>
</template>

<script>
import { getOrderList, shipOrder, refundOrder } from '../../../api/admin'

export default {
  data() {
    return {
      orderList: [],
      currentStatus: null,
      loading: false
    }
  },
  onShow() {
    this.loadOrders()
  },
  methods: {
    async loadOrders() {
      this.loading = true
      try {
        const res = await getOrderList(this.currentStatus, null)
        this.orderList = res.data || []
      } catch (e) {
        console.error('加载订单失败', e)
      } finally {
        this.loading = false
      }
    },

    filterByStatus(status) {
      this.currentStatus = status
      this.loadOrders()
    },

    getStatusText(status) {
      const map = {
        0: '待支付',
        1: '已支付',
        2: '已发货',
        3: '已完成',
        4: '已取消',
        5: '已退款'
      }
      return map[status] || '未知'
    },

    handleShip(item) {
      uni.showModal({
        title: '确认发货',
        content: `确定对订单 ${item.orderNo} 执行发货操作吗？`,
        success: async (res) => {
          if (res.confirm) {
            try {
              await shipOrder(item.id)
              uni.showToast({ title: '发货成功', icon: 'success' })
              this.loadOrders()
            } catch (e) {
              console.error('发货失败', e)
            }
          }
        }
      })
    },

    handleRefund(item) {
      uni.showModal({
        title: '确认退款',
        content: `确定对订单 ${item.orderNo} 执行退款操作吗？`,
        success: async (res) => {
          if (res.confirm) {
            try {
              await refundOrder(item.id)
              uni.showToast({ title: '退款成功', icon: 'success' })
              this.loadOrders()
            } catch (e) {
              console.error('退款失败', e)
            }
          }
        }
      })
    },

    navigateTo(url) {
      uni.redirectTo({ url })
    }
  }
}
</script>

<style scoped>
.admin-order {
  min-height: 100vh;
  background: #f5f6fa;
  padding-bottom: 120rpx;
}

.page-header {
  background: #fff;
  padding: 30rpx;
  border-bottom: 1rpx solid #eee;
}

.page-title {
  font-size: 36rpx;
  font-weight: bold;
  color: #333;
}

.filter-bar {
  display: flex;
  background: #fff;
  padding: 16rpx 24rpx;
  margin-bottom: 16rpx;
  overflow-x: auto;
}

.filter-item {
  flex-shrink: 0;
  padding: 12rpx 24rpx;
  font-size: 24rpx;
  color: #666;
  border-radius: 24rpx;
  margin-right: 16rpx;
  background: #f5f5f5;
}

.filter-item.active {
  background: #ff6600;
  color: #fff;
}

.order-list {
  padding: 0 24rpx;
}

.order-card {
  background: #fff;
  border-radius: 12rpx;
  padding: 24rpx;
  margin-bottom: 16rpx;
}

.order-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16rpx;
  padding-bottom: 16rpx;
  border-bottom: 1rpx solid #f5f5f5;
}

.order-no {
  font-size: 26rpx;
  color: #333;
  font-weight: bold;
}

.order-status {
  font-size: 24rpx;
  padding: 4rpx 16rpx;
  border-radius: 4rpx;
}

.status-0 {
  background: #fff7e6;
  color: #ff9900;
}

.status-1 {
  background: #e6f7e6;
  color: #07c160;
}

.status-2 {
  background: #e6f0ff;
  color: #1890ff;
}

.status-3 {
  background: #f0f0f0;
  color: #666;
}

.status-4 {
  background: #f5f5f5;
  color: #999;
}

.status-5 {
  background: #ffe6e6;
  color: #ee0a24;
}

.order-body {
  margin-bottom: 16rpx;
}

.order-info {
  display: flex;
  flex-wrap: wrap;
  gap: 16rpx;
}

.info-item {
  font-size: 24rpx;
  color: #666;
}

.order-footer {
  display: flex;
  justify-content: flex-end;
  gap: 16rpx;
  padding-top: 16rpx;
  border-top: 1rpx solid #f5f5f5;
}

.action-btn {
  height: 56rpx;
  line-height: 56rpx;
  font-size: 24rpx;
  border-radius: 6rpx;
  padding: 0 32rpx;
}

.ship-btn {
  background: #1890ff;
  color: #fff;
  border: none;
}

.refund-btn {
  background: #fff;
  color: #ee0a24;
  border: 1rpx solid #ee0a24;
}

.empty {
  text-align: center;
  padding: 100rpx 0;
  color: #999;
  font-size: 28rpx;
}

.admin-nav {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  display: flex;
  background: #fff;
  border-top: 1rpx solid #eee;
  height: 100rpx;
}

.nav-item {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 26rpx;
  color: #666;
}

.nav-item.active {
  color: #ff6600;
  font-weight: bold;
}
</style>
